import re

def count_politicians(articles, politician_names):
    # Create a set of lowercase politician names for case-insensitive matching
    lowercase_politicians = {name.lower() for name in politician_names}

    # Initialize a dictionary to store counts
    counts = {}

    # Process each article
    for article in articles:
        # Extract all words from the article
        words = re.findall(r'\b\w+\b', article)

        # Convert all words to lowercase for case-insensitive matching
        lowercase_words = [word.lower() for word in words]

        # Check for matching politician names
        for word in lowercase_words:
            if word in lowercase_politicians:
                # Increment the count for the politician
                counts[word] = counts.get(word, 0) + 1

    return counts
